// â”€â”€ helpers â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
const normalize = (v, fb = '') => (v == null ? fb : String(v).trim()) || fb;
const clip      = (v, max = 12000) => { const s = normalize(v); return s.length > max ? s.slice(0, max) + 'â€¦' : s; };
const safeInt   = (v, fb = 0)  => { const n = Number.parseInt(v, 10); return Number.isFinite(n) ? n : fb; };

function splitUserPoints(text, maxItems = 10) {
  if (!text) return [];
  const seen = new Set();
  return text.split(/\n/)
    .map(l => l.replace(/^[-*â€¢\d]+[.)\s]+/, '').trim())
    .filter(l => l.length > 3 && l.length < 300 && !seen.has(l) && seen.add(l))
    .slice(0, maxItems);
}

function inferTextFromFile(nome, mime, b64) {
  if (!b64) return '';
  const textMimes = ['text/', 'application/json', 'application/xml'];
  const textExts  = ['.txt', '.md', '.json', '.csv', '.xml', '.html', '.htm', '.rtf'];
  const ext = nome ? nome.toLowerCase().slice(nome.lastIndexOf('.')) : '';
  const isText = (mime && textMimes.some(m => mime.startsWith(m))) || textExts.includes(ext);
  if (!isText) return '';
  try {
    const decoded = Buffer.from(b64, 'base64').toString('utf-8');
    return decoded.slice(0, 15000);
  } catch { return ''; }
}

// â”€â”€ extrair payload â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
const item = $input.first();
const raw  = item.json?.body ?? item.json ?? {};
const now  = new Date().toISOString();

// â”€â”€ normalizar campos â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
const numero_processo   = normalize(raw.numero_processo);
const autor             = normalize(raw.autor);
const reu               = normalize(raw.reu, 'Nao informado');
const tipo_acao         = normalize(raw.tipo_acao);
const fatos             = clip(raw.fatos, 12000);
const pedido_autor      = clip(raw.pedido_autor, 8000);
const texto_editado     = clip(raw.texto_editado_ao_vivo, 12000);
const modelo_mae_texto  = clip(raw.modelo_mae_texto || process.env.MODELO_MAE_CONTESTACAO || '', 15000);

// â”€â”€ arquivo base â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
const arq_nome    = normalize(raw.arquivo_base_nome);
const arq_mime    = normalize(raw.arquivo_base_mime_type, 'application/octet-stream');
const arq_b64     = normalize(raw.arquivo_base_conteudo_base64);
const arq_tamanho = safeInt(raw.arquivo_base_tamanho_bytes, 0);
const MAX_BYTES   = 10 * 1024 * 1024;

// â”€â”€ validar campos obrigatorios â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
const erros = [];
const CNJ   = /^\d{7}-\d{2}\.\d{4}\.\d\.\d{2}\.\d{4}$/;

if (!numero_processo)                erros.push('numero_processo obrigatorio');
else if (!CNJ.test(numero_processo)) erros.push('numero_processo fora do padrao CNJ ex: 0001234-56.2026.8.00.0000');
if (!autor)       erros.push('autor obrigatorio');
if (!tipo_acao)   erros.push('tipo_acao obrigatorio');
if (!fatos)       erros.push('fatos obrigatorio');
if (!pedido_autor) erros.push('pedido_autor obrigatorio');

if (arq_nome && !arq_b64)    erros.push('arquivo_base_nome informado mas arquivo_base_conteudo_base64 ausente');
if (arq_b64  && !arq_nome)   erros.push('arquivo_base_conteudo_base64 informado mas arquivo_base_nome ausente');
if (arq_tamanho > MAX_BYTES) erros.push(`arquivo_base excede 10 MB (${arq_tamanho} bytes)`);

if (erros.length > 0) {
  return [{ json: { status: 'erro_validacao', mensagem: 'Falha de validacao.', erros, recebido_em: now } }];
}

const conteudo_texto = inferTextFromFile(arq_nome, arq_mime, arq_b64);
const pontos_usuario = splitUserPoints(texto_editado, 10);

return [{
  json: {
    status: 'entrada_validada',
    contexto: {
      numero_processo, autor, reu, tipo_acao, fatos, pedido_autor,
      texto_editado_ao_vivo: texto_editado, pontos_usuario, modelo_mae_texto,
      arquivo_base: arq_nome ? { nome: arq_nome, mime_type: arq_mime, tamanho_bytes: arq_tamanho, conteudo_texto } : null
    },
    recebido_em: now
  }
}];

// â”€â”€ pass-through em caso de erro de validacao â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
const envelope = $input.first().json;
if (envelope.status === 'erro_validacao') {
  return [{ json: envelope }];
}

const { contexto, recebido_em } = envelope;

// â”€â”€ ler credenciais do Supabase â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
const readEnv = (key, fb = '') => {
  try {
    if (typeof $vars !== 'undefined' && $vars && $vars[key]) return String($vars[key]).trim();
    return ($env && $env[key]) ? String($env[key]).trim() : (process.env[key] || fb);
  } catch { return process.env[key] || fb; }
};

const SUPABASE_URL = readEnv('SUPABASE_URL') || readEnv('SUPABASE_BASE_URL');
const SUPABASE_KEY = readEnv('SUPABASE_PUBLISHABLE_KEY') || readEnv('SUPABASE_ANON_KEY') || readEnv('SUPABASE_SERVICE_ROLE_KEY');

if (!SUPABASE_URL || !SUPABASE_KEY) {
  return [{
    json: {
      ...envelope,
      defesas_anteriores: { status: 'sem_credenciais', detalhe: 'SUPABASE_URL ou SUPABASE_PUBLISHABLE_KEY nao configuradas', casos: [], total: 0 }
    }
  }];
}

// â”€â”€ consultar contestacoes anteriores com mesmo tipo_acao â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
// Sanitiza inputs que serao concatenados na URL Supabase REST. encodeURIComponent ja escapa
// caracteres URL, mas preferimos rejeitar caracteres fora do alfabeto juridico esperado para
// minimizar superficie de injection na sintaxe PostgREST (operadores como eq./ilike. dependem de pontuacao).
const SAFE_TIPO_RX = /^[\w\sÀ-ÿ\-().]{1,100}$/;
const SAFE_NUMERO_RX = /^[\w\-./]{1,40}$/;
const tipoRaw = String(contexto.tipo_acao || '').trim();
const numeroRaw = String(contexto.numero_processo || '').trim();
if (!SAFE_TIPO_RX.test(tipoRaw) || !SAFE_NUMERO_RX.test(numeroRaw)) {
  return [{
    json: {
      ...envelope,
      defesas_anteriores: { status: 'input_invalido', detalhe: 'tipo_acao ou numero_processo com caracteres inesperados', casos: [], total: 0 }
    }
  }];
}
const tipo = encodeURIComponent(tipoRaw);
const numero = encodeURIComponent(numeroRaw);
const url = `${SUPABASE_URL}/rest/v1/contestacoes` +
  `?select=numero_processo,tipo_acao,fatos,pedido_autor,n8n_resposta,status,criado_em` +
  `&status=eq.ok` +
  `&tipo_acao=eq.${tipo}` +
  `&numero_processo=neq.${numero}` +
  `&order=criado_em.desc` +
  `&limit=5`;

const controller = new AbortController();
const timer = setTimeout(() => controller.abort(), 8000);

let defesas_anteriores;
try {
  const resp = await fetch(url, {
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': `Bearer ${SUPABASE_KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'return=representation'
    },
    signal: controller.signal
  });

  if (!resp.ok) {
    const body = await resp.text().catch(() => '');
    defesas_anteriores = { status: 'erro_http', detalhe: `HTTP ${resp.status}: ${body.slice(0, 150)}`, casos: [], total: 0 };
  } else {
    const rows = await resp.json();
    if (!rows || rows.length === 0) {
      defesas_anteriores = { status: 'sem_resultados', detalhe: 'Nenhuma defesa anterior encontrada para este tipo_acao', casos: [], total: 0 };
    } else {
      const casos = rows.map(row => {
        const nr = row.n8n_resposta || {};
        const minuta = nr.minuta || {};
        return {
          numero_processo: row.numero_processo,
          tipo_acao: row.tipo_acao,
          fatos_resumo: (row.fatos || '').slice(0, 500),
          pedido_autor_resumo: (row.pedido_autor || '').slice(0, 300),
          tese_central: minuta.tese_central || '',
          resumo_estrategico: minuta.resumo_estrategico || '',
          riscos: (minuta.riscos || []).slice(0, 3),
          criado_em: row.criado_em
        };
      });
      defesas_anteriores = { status: 'sucesso', detalhe: `${casos.length} defesa(s) encontrada(s)`, casos, total: casos.length };
    }
  }
} catch (e) {
  defesas_anteriores = {
    status: e.name === 'AbortError' ? 'timeout_8s' : 'erro_conexao',
    detalhe: e.message,
    casos: [], total: 0
  };
} finally {
  clearTimeout(timer);
}

return [{
  json: {
    ...envelope,
    defesas_anteriores
  }
}];

// â”€â”€ helpers â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
const readEnv = (key, fb = '') => {
  try {
    if (typeof $vars !== 'undefined' && $vars && $vars[key]) return String($vars[key]).trim();
    return ($env && $env[key]) ? String($env[key]).trim() : (process.env[key] || fb);
  } catch { return process.env[key] || fb; }
};
const stripFences = s => {
  const cleaned = String(s || '').trim().replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim();
  const first = cleaned.indexOf('{');
  const last = cleaned.lastIndexOf('}');
  if (first === -1 || last === -1 || last < first) return cleaned;
  return cleaned.slice(first, last + 1);
};

// â”€â”€ pass-through erro validacao â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
const envelope = $input.first().json;
if (envelope.status === 'erro_validacao') return [{ json: envelope }];

const { contexto, recebido_em, defesas_anteriores } = envelope;

// â”€â”€ configuracao Claude â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
const ANTHROPIC_KEY = readEnv('ANTHROPIC_API_KEY') || readEnv('CLAUDE_API_KEY') || readEnv('CLAUDE_SECRET_KEY');
const CLAUDE_MODEL  = readEnv('CLAUDE_MODEL') || readEnv('ANTHROPIC_MODEL') || 'claude-sonnet-4-6';
const BASE_URL      = (readEnv('ANTHROPIC_BASE_URL') || 'https://api.anthropic.com').replace(/\/$/, '');
const API_VERSION   = readEnv('ANTHROPIC_VERSION') || '2023-06-01';
const MAX_TOKENS    = Math.max(700, parseInt(readEnv('CLAUDE_MAX_TOKENS', '6000'), 10) || 6000);
const TEMPERATURE   = parseFloat(readEnv('CLAUDE_TEMPERATURE', '0.12')) || 0.12;
const TIMEOUT_MS    = Math.max(10000, parseInt(readEnv('CLAUDE_TIMEOUT_MS', '120000'), 10) || 45000);

// â”€â”€ system prompt â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
const SYSTEM_PROMPT = `Voce e um agente juridico especialista em contestacoes civeis no Brasil, integrado ao sistema AutoJuri.

CONTEXTO DO SISTEMA AUTOJURI:
- Backend: FastAPI porta 8000. Frontend: React+Vite porta 5173. Automacao: n8n porta 5678.
- Banco: PostgreSQL Supabase. Auth: Supabase JWT Bearer.

ROTAS DO BACKEND:
- POST /api/gerar-contestacao  -> envia ao n8n e persiste no banco
- GET  /api/contestacoes/resumo -> dashboard
- POST /api/usuarios/cadastro / login / logout
- GET  /api/usuarios/sessao
- POST /api/suporte/contato

SCHEMA BANCO (tabela contestacoes):
  id, usuario_id, numero_processo, autor, reu, tipo_acao, fatos, pedido_autor,
  arquivo_base, texto_editado_ao_vivo,
  status (ok|processando|erro|erro_validacao|rejeitado),
  n8n_resposta (JSONB), criado_em (TIMESTAMPTZ)

SUA TAREFA: Redigir minuta de contestacao para revisao humana.
Regras:
- Objetividade, clareza, sem inventar fatos, sem inventar jurisprudencia ou citacoes numericas.
- Se MODELO_MAE existir, preserve estilo e estrutura.
- Se TEXTO_PETICAO_BASE existir, identifique pontos centrais e responda tecnicamente.
- Priorize os pontos listados em pontos_usuario.
- Se houver DEFESAS_ANTERIORES_SIMILARES, use como referencia de tese e estrategia (nunca copie ipsis litteris).

Responda SOMENTE JSON valido (sem markdown, sem codeblock) com exatamente estas chaves:
{
  "resumo_estrategico": "...",
  "tese_central": "...",
  "pontos_atendidos": ["..."],
  "sintese": "...",
  "fundamentos": "...",
  "pedidos": "...",
  "observacoes": "...",
  "riscos": ["..."]
}`;

// â”€â”€ montar contexto das defesas anteriores â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
let defesasCtx = '';
const casos = defesas_anteriores?.casos || [];
if (casos.length > 0) {
  defesasCtx = '\n\nDEFESAS_ANTERIORES_SIMILARES (mesmo tipo_acao, para referencia):\n' +
    casos.map((c, i) => [
      `Caso ${i+1}: ${c.numero_processo} (${c.tipo_acao})`,
      `  Fatos resumo: ${c.fatos_resumo}`,
      `  Pedido autor: ${c.pedido_autor_resumo}`,
      `  Tese central usada: ${c.tese_central}`,
      `  Estrategia: ${c.resumo_estrategico}`,
      `  Riscos: ${(c.riscos || []).join('; ')}`
    ].join('\n')).join('\n\n');
}

// â”€â”€ montar mensagem do usuario â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
const casoJson = JSON.stringify({
  numero_processo: contexto.numero_processo,
  autor: contexto.autor,
  reu: contexto.reu,
  tipo_acao: contexto.tipo_acao,
  fatos: contexto.fatos,
  pedido_autor: contexto.pedido_autor,
  pontos_usuario: contexto.pontos_usuario,
  texto_editado_ao_vivo: contexto.texto_editado_ao_vivo || '',
  texto_peticao_base: contexto.arquivo_base?.conteudo_texto || '',
  modelo_mae_texto: contexto.modelo_mae_texto || ''
}, null, 2);

const USER_MSG = `CASO_JSON:\n${casoJson}${defesasCtx}`;

// â”€â”€ fallback local â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
function buildFallback(motivo) {
  const c = contexto;
  const pontosStr = (c.pontos_usuario || []).map((p, i) => `  ${i+1}. ${p}`).join('\n') || '  (nenhum ponto especificado)';
  const tesesAnteriores = casos.length > 0 ? `\n\nDefesas anteriores similares indicam tese: ${casos[0].tese_central}` : '';
  return {
    resumo_estrategico: `Contestacao ao processo ${c.numero_processo} (${c.tipo_acao}). Estrategia: improcedencia dos pedidos autorais.`,
    tese_central: 'Improcedencia dos pedidos autorais por ausencia de fundamento legal e factual.' + tesesAnteriores,
    pontos_atendidos: c.pontos_usuario || [],
    sintese: `Trata-se de contestacao referente ao processo ${c.numero_processo}, proposta por ${c.autor} em face de ${c.reu}, versando sobre ${c.tipo_acao}.`,
    fundamentos: `I â€“ DO MERITO\n\nFatos narrados: ${c.fatos.slice(0, 800)}\n\nPontos do contestante:\n${pontosStr}\n\nNao ha embasamento juridico para o pedido formulado.`,
    pedidos: `Ante o exposto, requer:\n(i) O recebimento da presente contestacao;\n(ii) A improcedencia de todos os pedidos do autor;\n(iii) Honorarios advocaticios;\n(iv) Producao de provas.`,
    observacoes: `Minuta em modo fallback local (motivo: ${motivo}). Revise antes de protocolar.`,
    riscos: ['Revisar prazos processuais', 'Verificar jurisprudencia atual', 'Confirmar documentos']
  };
}

// â”€â”€ chamar API Claude â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
let minutaRaw = null;
let provider  = 'fallback_local';
let apiError  = null;

if (!ANTHROPIC_KEY) {
  apiError = 'ANTHROPIC_API_KEY nao configurada';
} else {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), TIMEOUT_MS);
  try {
    const resp = await fetch(`${BASE_URL}/v1/messages`, {
      method: 'POST',
      headers: { 'x-api-key': ANTHROPIC_KEY, 'anthropic-version': API_VERSION, 'content-type': 'application/json' },
      body: JSON.stringify({ model: CLAUDE_MODEL, max_tokens: MAX_TOKENS, temperature: TEMPERATURE, system: SYSTEM_PROMPT, messages: [{ role: 'user', content: USER_MSG }] }),
      signal: controller.signal
    });
    if (!resp.ok) { const e = await resp.text().catch(() => ''); throw new Error(`HTTP ${resp.status}: ${e.slice(0, 200)}`); }
    const payload = await resp.json();
    minutaRaw = (payload.content || []).filter(b => b.type === 'text').map(b => b.text).join('').trim();
    if (!minutaRaw) throw new Error('resposta_ia_sem_conteudo');
    provider = 'claude';
  } catch (e) {
    apiError = e.name === 'AbortError' ? `timeout_${TIMEOUT_MS}ms` : e.message;
  } finally {
    clearTimeout(timer);
  }
}

// â”€â”€ parsear resposta â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
let minuta;
if (provider === 'claude' && minutaRaw) {
  try { minuta = JSON.parse(stripFences(minutaRaw)); }
  catch (e) { apiError = `json_parse_error: ${e.message}`; provider = 'fallback_local'; }
}
if (!minuta) minuta = buildFallback(apiError || 'sem_chave');

// â”€â”€ limitar tamanhos â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
const clipStr = (v, max) => typeof v === 'string' && v.length > max ? v.slice(0, max) + 'â€¦' : (v || '');
minuta.resumo_estrategico = clipStr(minuta.resumo_estrategico, 3000);
minuta.tese_central       = clipStr(minuta.tese_central, 2000);
minuta.sintese            = clipStr(minuta.sintese, 10000);
minuta.fundamentos        = clipStr(minuta.fundamentos, 15000);
minuta.pedidos            = clipStr(minuta.pedidos, 8000);
minuta.observacoes        = clipStr(minuta.observacoes, 6000);
minuta.pontos_atendidos   = Array.isArray(minuta.pontos_atendidos) ? minuta.pontos_atendidos.slice(0, 12) : [];
minuta.riscos             = Array.isArray(minuta.riscos) ? minuta.riscos.slice(0, 6) : [];

return [{
  json: {
    status: 'agente_processado',
    contexto, recebido_em, defesas_anteriores,
    engine_ia: {
      provider, model: provider === 'claude' ? CLAUDE_MODEL : 'deterministico',
      endpoint: provider === 'claude' ? `${BASE_URL}/v1/messages` : null,
      temperature: TEMPERATURE, max_tokens: MAX_TOKENS, api_error: apiError || null
    },
    minuta
  }
}];
